const BumpAllocator = struct {
    buffer: []u8,
    offset: usize = 0,

    pub fn alloc(self: *BumpAllocator, size: usize) ?[]u8 {
        if (self.offset + size > self.buffer.len) return null;
        const ptr = self.buffer[self.offset..][0..size];
        self.offset += size;
        return ptr;
    }

    pub fn reset(self: *BumpAllocator) void {
        self.offset = 0;
    }
};

fn allocFn(ctx: *anyopaque, len: usize, ptr_align: u8, ret_addr: usize) ?[*]u8 {
    _ = ret_addr;
    const self: *MyAllocator = @ptrCast(@alignCast(ctx));
    const aligned_offset = std.mem.alignForward(usize, self.offset, @as(usize, 1) << @intCast(ptr_align));
    if (aligned_offset + len > self.buffer.len) return null;
    const ptr = self.buffer.ptr + aligned_offset;
    self.offset = aligned_offset + len;
    return ptr;
}
